mapper.select:
SELECT pa.*, dc.cat_name AS categoryName, al.loc_name AS locationName, p.project_name AS projectName, u.real_name AS custodianName FROM physical_asset pa LEFT JOIN device_category dc ON pa.category_id = dc.id LEFT JOIN asset_location al ON pa.location_id = al.id LEFT JOIN project p ON pa.project_id = p.id LEFT JOIN sys_user u ON pa.custodian_id = u.id WHERE pa.deleted = 0
AND pa.asset_name LIKE CONCAT('%', #{assetName}, '%')
AND pa.category_id = #{categoryId}
AND pa.status = #{status}
AND pa.project_id = #{projectId}
ORDER BY pa.created_at DESC

SELECT COUNT(*)
FROM physical_asset pa
WHERE pa.deleted = 0

    AND pa.asset_name LIKE CONCAT('%', #{assetName}, '%')


    AND pa.category_id = #{categoryId}


    AND pa.status = #{status}


    AND pa.project_id = #{projectId}
